class PrestashopService {
  async searchProducts(query, limit = 50) {
    await new Promise(resolve => setTimeout(resolve, 300));
    if (!query || query.length < 2) {
      return [];
    }
    const lowerQuery = query.toLowerCase();
    const filtered = MOCK_PRODUCTS.filter(product => product.name.toLowerCase().includes(lowerQuery) || product.reference.toLowerCase().includes(lowerQuery));
    return filtered.slice(0, limit);
  }
  async getProduct(productId) {
    await new Promise(resolve => setTimeout(resolve, 200));
    const product = MOCK_PRODUCTS.find(p => p.id === productId);
    if (!product) {
      throw new Error('Product not found');
    }
    return product;
  }
}
export default new PrestashopService();
